"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[328],{7328:function(e,t,i){i.d(t,{J:function(){return c},LanguageProvider:function(){return l}});var a=i(7437),n=i(2265),o=i(4011);let r=(0,n.createContext)(null),s="eitzikna-lang";function l(e){let{children:t}=e,[i,l]=(0,n.useState)("he"),[c,d]=(0,n.useState)(!1);(0,n.useEffect)(()=>{let e=localStorage.getItem(s);("he"===e||"en"===e)&&l(e),d(!0)},[]),(0,n.useEffect)(()=>{if(!c)return;let e=document.documentElement;e.lang=i,e.dir="he"===i?"rtl":"ltr",localStorage.setItem(s,i)},[i,c]);let h=o.JG[i],m="he"===i?"rtl":"ltr";return(0,a.jsx)(r.Provider,{value:{lang:i,setLang:e=>l(e),t:h,dir:m},children:t})}function c(){let e=(0,n.useContext)(r);if(!e)throw Error("useLang must be used inside LanguageProvider");return e}},4011:function(e,t,i){i.d(t,{Dl:function(){return s},JG:function(){return a},NY:function(){return o},UE:function(){return n},uw:function(){return l},xK:function(){return r}});let a={he:{nav:{services:"שירותים",pillars:"הגישה הקלינית",conditions:"מצבים",about:"אודות",contact:"צור קשר",cta:"לשיחת ייעוץ"},hero:{headline:"אבא שלך מגיע ליותר ממטפל",sub:"Eitzikna מספקת ניהול טיפול גריאטרי פרטי ליום מלא בבית. אנשי המקצוע שלנו מיישמים בעצמם את התוכנית הרפואית, נוכחים בפגישות לצד הרופאים המטפלים, ומדווחים לבני המשפחה בכתב בכל יום ביקור.",ctaPrimary:"קביעת שיחת ייעוץ"},problem:{eyebrow:"האתגר",headline:"הטיפול בהורה מבוגר לא צריך לאכול את כל החיים שלכם",body:"הפיזיותרפיסט מגיע פעם בשבוע ומשאיר הוראות. הדיאטנית שולחת תפריט. הרופא רושם תרופה. אבל מי באמת מבצע את הכל יום אחר יום? מי מתעד? מי מתאם בין כל הצוות הרפואי? בדרך כלל — אתם. מהמשרד, מחו״ל, בלילות."},approach:{eyebrow:"הגישה הקלינית שלנו",headline:"יישום מעשי. תיעוד יומי. אחריות קלינית מלאה.",body:"במקום לתאם בין חמישה אנשי מקצוע ולקוות שהמידע יזרום ביניהם — Eitzikna נוכחת בכל פגישה רפואית, מבצעת את כל הטיפולים שנקבעו, מתעדת באופן רציף, ומדווחת אליכם בכתב בכל יום ביקור.",bullets:["יישום מעשי של כל תרגילי הפיזיותרפיה והריפוי בעיסוק שנקבעו, ישירות תחת הנחיית המומחה","הכנת ארוחות לפי תפריט רפואי; מעקב אחר צריכה, הידרציה והפרשה; זיהוי מוקדם של סימנים קליניים","ניהול מלא של לוח התרופות — מינונים, מתן, מעקב אחר תופעות לוואי, תיאום עם בית המרקחת","נוכחות בפגישות רפואיות לצד רופא המשפחה, גריאטר, פיזיותרפיסט ודיאטנית","תיעוד קליני יומי — סימפטומים, סימנים חיוניים, קוגניציה, מצב רוח והתקדמות טיפולית","דיווח מובנה לבני המשפחה בוואטסאפ, באימייל או בשיחה — בקצב שמתאים לכם"]},services:{title:"מה אנחנו מבצעים בכל יום ביקור",subtitle:"תוכנית טיפול מקיפה, מבוצעת בבית, על ידי מקצוען עם רקע קליני ישיר.",items:[{title:"יישום פיזיותרפיה קליני",desc:"נוכחות בכל פגישת פיזיותרפיה רפואית, למידת הטכניקה ישירות מהמומחה, וביצוע מדויק של התרגילים בבית במהלך השבוע — בעצימות הנכונה, ברצף הנכון, ללא הפסקות בלוח הטיפול."},{title:"ריפוי בעיסוק וגירוי קוגניטיבי",desc:"משחקי לוח, פעילויות מוטוריות עדינות, אימון זיכרון ותרגול תפקודי — נבחרים לפי המצב הקוגניטיבי הנוכחי, מותאמים בהמשך לפי שינויים במצב."},{title:"תזונה רפואית והכנת ארוחות",desc:"בתאום עם הדיאטנית הקלינית. מעקב אחר צריכה, הידרציה, והפרשה — זיהוי מוקדם של התייבשות, עצירות וחוסר ספיגה — ויישום מלא של התפריט הרפואי."},{title:"ניהול תרופות ועמידה במינון",desc:"פיקוח מלא על לוח התרופות, וידוא נטילה, מעקב אחר תופעות לוואי, תיאום מילוי מרשמים, ותקשורת ישירה עם בית המרקחת והרופא הרושם."},{title:"ניידות, העברות ומניעת נפילות",desc:"מיומנות בהעברות בטוחות, הליכה מלווה, התאמת הסביבה הביתית למניעת נפילות. הכשרה ייעודית לטיפול במטופלי פרקינסון, מוגבלי תנועה ומטופלי פוסט-שבץ."},{title:"ליווי רוחני ומסורתי",desc:"סדר תפילות יומי, ליווי לבית הכנסת, לימוד גמרא או חומש, ושמירה על הקשר הרוחני שמהווה עוגן בחיי היום-יום של המטופל. מותאם לרקע ולמסורת המשפחה."},{title:"פעילות חוץ טיפולית",desc:"הליכות יומיות, יציאה לפארק, חשיפה מבוקרת לאוויר צח וסביבה חברתית, סידורים בקהילה — חלק אינטגרלי מהתוכנית הקלינית."},{title:"ליווי עומק ונוכחות קוגניטיבית",desc:"נוכחות מלאה ופעילה — לא רק להיות במקום. שיחות, שירה משותפת, תיעוד היסטוריה אישית למזכרת משפחתית, האזנה סבלנית. גירוי קוגניטיבי באמצעות קשר אנושי אמיתי."},{title:"מנוחה מובנית ושיקום יומי",desc:"זמני שינה ומנוחה מתוזמנים, סביבה רגועה, תזמון נכון של הפסקות בין פעילויות — לאיזון של עומס פיזי וקוגניטיבי לאורך כל יום הטיפול."}]},pillars:{title:"ארבעת עמודי הטיפול",subtitle:"מתודולוגיה קלינית מובנית — היא הבסיס של כל תוכנית טיפול שאנחנו מתכננים ומיישמים.",items:[{number:"01",title:"פיקוח רפואי וטיפול אישי",summary:"הניהול הקליני היומיומי של בריאות המטופל — ממתן התרופה הראשונה בבוקר ועד דיווח הסיכום בערב.",details:[{h:"ניהול תרופות",b:"פיקוח מלא על לוח הזמנים, וידוא מינונים, מעקב אחר תופעות לוואי, תיאום עם בית המרקחת והרופא הרושם, ובקרה רציפה לעמידה בפרוטוקול."},{h:"היגיינה בכבוד",b:"תמיכה מלאה בלבוש, רחצה, וטיפול בבריחת שתן — בדגש מוחלט על כבוד המטופל ונוחותו הפיזית בכל פעולה."},{h:"ניידות ובטיחות",b:"הכשרה בהעברות בטוחות, הערכת סיכוני נפילה, התאמות בסביבה הביתית, וליווי בהליכה — לשמירה על העצמאות התפקודית."},{h:"תיעוד ודיווח קליני",b:"יומן יומי מפורט: סימפטומים, סימנים חיוניים, מינונים, ביצוע פיזיותרפיה, צריכה תזונתית, מצב רוח וקוגניציה — נמסר לצוות הרפואי ולמשפחה."}]},{number:"02",title:"מערכת עיכול ותזונה — היסוד הקליני",summary:"תפקוד עיכולי ותזונתי יציב הוא תנאי מקדים לספיגת תרופות, לעמידות בשיקום, ולניהול מחלות כרוניות. אנחנו מתייחסים לזה כיסוד של כל תוכנית טיפול.",details:[{h:"מעקב צריכה והידרציה",b:"מעקב יומי אחר צריכה קלורית ונוזלית מול התפריט הרפואי, עם זיהוי מוקדם של מגמות שמשפיעות על יעילות תרופות, על שיקום, ועל יציבות מטבולית."},{h:"תפקוד מערכת העיכול והפרשה",b:"מעקב סדיר אחר הפרשה ותפקוד מערכת העיכול. זיהוי מוקדם של עצירות, חוסר ספיגה, וסימני התייבשות — הסלמה לרופא לפני הידרדרות קלינית."},{h:"תיאום קליני",b:"תיאום ישיר עם הדיאטנית או התזונאית הרושמת לגבי התפריט, תוספי מזון, והתאמות בהתאם לשינויים במצב הרפואי."}]},{number:"03",title:"יישום פיזיותרפיה ותנועה טיפולית",summary:"נוכחות בפגישות עם המומחה — למידת הטכניקה ישירות. יישום מלא בבית במהלך השבוע. שום תרגיל לא ״הולך לאיבוד״ בין הפגישות.",details:[{h:"יישום קליני",b:"נוכחות בפגישות פיזיותרפיה ו-OT מקצועיות לצורך למידת השגרות ישירות מהמומחה — מבטיחה ביצוע נכון של התרגילים בבית בעצימות ובמינון שנקבעו."},{h:"תנועה אינטגרטיבית",b:"יישום שגרות מתיחה מתואמות ומסאז׳ טיפולי לאורך כל יום הטיפול — לשמירה על גמישות מפרקית, טווחי תנועה, וזרימת דם."},{h:"שגרות מותאמות",b:"כשהשגרה הסטנדרטית לא ניתנת לביצוע, החלפה בתנועות חלופיות שתואמו מראש עם המומחה — להמשכיות טיפולית בלי מאמץ יתר."}]},{number:"04",title:"מסגרת, יציאות ונוכחות קוגניטיבית",summary:"יום מובנה. יציאות עם מטרה. נוכחות אנושית אמיתית — של מישהו שמכיר את המטופל לעומק.",details:[{h:"שגרה פעילה",b:"בניית לוח זמנים יומי צפוי שמתעדף יציאות ופעילויות ייעודיות לגירוי גופני וקוגניטיבי — בקצב המתאים לכל מטופל."},{h:"ליווי עומק",b:"נוכחות מלאה וקשובה. שיחות, שירה משותפת, תיעוד היסטוריה אישית למזכרת משפחתית, האזנה סבלנית — קשר אנושי אמיתי, לא רק נוכחות פיזית."},{h:"ליווי רוחני",b:"תפילה ולימוד יומיים, ליווי לבית הכנסת, שמירה על הקשר הרוחני המשפחתי — מותאם לרקע ולמסורת של כל מטופל."}]}]},conditions:{title:"מצבים ותחומי טיפול",subtitle:"התמחות בניהול מקרים מורכבים פיזית וקוגניטיבית.",items:[{title:"מחלת פרקינסון",desc:"ניהול שלבי מחלה מתקדמים, תפעול מינוני L-Dopa, תיזמון פעילות בחלונות ה-on, ניהול תקופות ה-off."},{title:"דמנציה וירידה קוגניטיבית",desc:"אלצהיימר, דמנציה כלי-דם, גופי לואי, פרונטוטמפורלי. שגרות מבניות, גירוי קוגניטיבי, וניהול שינויים התנהגותיים לאורך התקדמות המחלה."},{title:"התאוששות פוסט-שבץ",desc:"יישום פיזיותרפיה שיקומית, ניהול אפזיה, שיקום מוטורי, ותיאום עם רופא משקם ועם הצוות הרב-מקצועי."},{title:"מוגבלות תנועה",desc:"מטופלים מרותקים לכיסא גלגלים או מוגבלי תנועה — העברות בטוחות, מניעת פצעי לחץ, שמירה על טווחי תנועה."},{title:"ניהול מחלות כרוניות",desc:"סוכרת, מחלות לב, COPD, אי-ספיקת כליות — ניהול תרופתי, מעקב יומי אחר סימנים חיוניים, והסלמה מוקדמת לרופא בעת שינוי במצב."},{title:"שיקום פוסט-אשפוז",desc:"גשר בטוח בין בית החולים והבית — תיאום הוצאה, יישום מלא של הוראות שחרור, ומעקב אחר סיבוכים אפשריים."}]},how:{title:"איך מתחילים",steps:[{t:"שיחת היכרות",b:"שיחה של 30 דקות איתכם להבין את המצב הרפואי, את האתגרים היומיומיים, ואת הציפיות מהליווי. ללא עלות, ללא התחייבות."},{t:"ביקור הערכה ובניית תוכנית",b:"ביקור בית עם המטופל, סקירת התיק הרפואי, ופגישה עם רופא המשפחה במידת הצורך — לקראת בניית תוכנית טיפול שבועית מלאה ומותאמת."},{t:"ביצוע, תיעוד, ודיווח",b:"ימי טיפול מלאים בבית בקצב המוסכם, ביצוע מלא של התוכנית הרפואית, תיעוד קליני שוטף, ודיווח מובנה למשפחה — וואטסאפ, אימייל או שיחה."}]},why:{title:"מה הופך את השירות לשונה",colA:"מטפל סיעודי רגיל",colB:"מנהל טיפול (מרחוק)",colC:"Eitzikna",rows:[["בדרך כלל לא יהודי, לא מוכר עם החיים והמסורת היהודית","יכול להיות או לא להיות מוכר עם הרקע היהודי של המטופל","יהודי, שומר תורה ומצוות, שולט לחלוטין בהקשר של מטופל יהודי"],["נוכחות בבית בלבד; אינו מבצע טיפולים קליניים","מתאם מרחוק; אינו מבצע טיפולים בעצמו","יישום מעשי בבית של כל טיפול שנקבע"],["אינו נוכח בפגישות רפואיות","תיאום בטלפון או באימייל; אינו נוכח פיזית","נוכחות בפגישות רפואיות לצד המטופל והרופאים"],["ללא תיאום עם הצוות הרפואי","תיאום תקופתי, בעיקר אדמיניסטרטיבי","תיאום ישיר ומתמשך עם כל צוות הטיפול"],["ללא תיעוד קליני יומי","הערות חודשיות בלבד","יומן קליני יומי — סימפטומים, מינונים, סימנים חיוניים, קוגניציה, התקדמות טיפולית"],["ללא דיווח למשפחה","סיכום חודשי","דיווח מובנה בכל יום ביקור"],["אחריות מוגבלת לנוכחות פיזית בלבד","אחריות מוגבלת לתיאום בלבד","אחריות קלינית מלאה לאורך כל חלון הטיפול היומי"]]},family:{title:"אנחנו עובדים בשיתוף מלא עם המשפחה",subtitle:"שקיפות מלאה ותקשורת רציפה — לא תכונה, אלא הליבה של השירות.",row1:{t:"דיווח לבני המשפחה בכל יום ביקור",b:"בכל יום ביקור — סיכום מסודר: מה בוצע, איך אבא הרגיש, אם היו שינויים בסימפטומים, מה הוחלט. בקצב שמתאים — וואטסאפ, אימייל או שיחה."},row2:{t:"תוכנית טיפול מתועדת ושקופה",b:"כל החלטה, כל מינון, כל תרגיל — מתועד בכתב. למשפחה גישה מלאה למסמך הטיפול בכל רגע, ויודעת בדיוק איפה אבא עומד."},closing:"כי טיפול אמיתי בהורה — מתחיל באמון של המשפחה."},founder:{eyebrow:"מי שעומד מאחורי השירות",headline:"דני דרטלר — מייסד Eitzikna",body:"Eitzikna בהובלתו של דני דרטלר — מקצוען יהודי, שומר תורה ומצוות, מבסיס ברמת בית שמש, המוקדש לטיפול גריאטרי מעשי במטופלים יהודים בביתם.\n\nהגישה שלנו מבוססת על אקטיבציה של המטופל: רואים את המצב מנקודת המבט שלו, ופועלים לטובתו בכל רגע. אנחנו לוקחים תפקיד אקטיבי בתמיכה בנוחות, בריאות, בטיחות ורווחה כללית. דרך אמפתיה, האזנה ונוכחות מלאה, כל מטופל מרגיש מובן, נתמך ומטופל באמת.\n\nאנחנו אמינים, קשובים, ומהירים ללמוד את השגרות, ההעדפות והצרכים הייחודיים של כל מטופל. הזהות היהודית המשותפת מאפשרת הבנה אמיתית של החיים הרוחניים, של דינמיקת המשפחה היהודית, ושל המסגרת הקהילתית — כל מה שמרכיב טיפול אמיתי שמכבד את המטופל.",credentials:"מבסיס ברמת בית שמש א׳ \xb7 משרת את אזור בית שמש, ביתר עילית, מודיעין עילית וירושלים"},references:{title:"מה אומרים בני המשפחה",subtitle:"הפניות מקצועיות וממשפחות מטופלים — זמינות בבקשה.",body:"נשמח לחבר אתכם ישירות עם משפחות שאנחנו עובדים או עבדנו איתן — שתשמעו מהן בעצמכם, בלי תיווך, על איך נראה השירות הזה ביום-יום אמיתי.",cta:"צרו קשר לבקשת הפניות"},faq:{title:"שאלות נפוצות",items:[{q:"מה ההבדל בין ניהול טיפול גריאטרי פרטי לבין מטפל סיעודי רגיל?",a:"מטפל סיעודי נוכח בבית ומספק עזרה בסיסית. ניהול טיפול גריאטרי פרטי הוא שירות קליני מלא — אנשי המקצוע מבצעים בעצמם את הטיפולים שנקבעו, נוכחים בפגישות רפואיות, מתעדים יומית, ומדווחים למשפחה. השירות מקיף יותר, אקטיבי יותר, ואחראי קלינית."},{q:"באילו מצבים יש ל-Eitzikna הכי הרבה ניסיון?",a:"מחלת פרקינסון בכל שלביה (כולל ניהול מינוני L-Dopa וחלונות on/off), דמנציה (אלצהיימר, דמנציה כלי-דם, גופי לואי, פרונטוטמפורלי), התאוששות פוסט-שבץ, מוגבלויות תנועה, וניהול מחלות כרוניות מורכבות."},{q:"האם אתם עובדים עם הרופאים הקיימים של אבא?",a:"בהחלט — זה חלק מרכזי מהשירות. אנחנו נוכחים בפגישות עם רופא המשפחה, גריאטר, פיזיותרפיסט ודיאטנית. מקבלים הוראות ישירות, מיישמים אותן בבית, ומדווחים חזרה. הצוות הרפואי הקיים מקבל מידע מדויק ועקבי."},{q:"איך נראה דיווח יומי?",a:"בכל יום ביקור: מינוני תרופות שניתנו, סימפטומים שצוינו, שינויים במצב רוח או קוגניציה, ביצוע פיזיותרפיה (אילו תרגילים, בכמה חזרות), צריכת מזון ושתייה, הפרשה, ופעילויות. הסיכום נמסר בוואטסאפ, באימייל או בשיחה — לפי הקצב שאתם מבקשים."},{q:"באילו אזורים אתם פועלים?",a:"רמת בית שמש א׳, בית שמש, ביתר עילית, מודיעין עילית, וירושלים. זמינות לקצרי-טווח גם באזורים נוספים — צרו קשר לבדיקה."},{q:"מה משך הטיפול ביום?",a:"אנחנו מספקים נוכחות יומית מלאה לאורך שעות היום. השירות מותאם להיות חלק עיקרי מהטיפול היומי במטופל. למשפחות שזקוקות גם לליווי לילי, אנחנו מתאמים את העבודה עם נותני שירות נוספים בקלות."},{q:"מה קורה במצב חירום?",a:"במצב חירום רפואי — קוראים למד״א מיידית. אנחנו זמינים טלפונית במהלך היום לכל שאלה דחופה, ובמהלך הביקור עצמו אנחנו מסלימים את כל מה שמצריך התייחסות רפואית מיידית לרופא המתאים."},{q:"כמה זה עולה?",a:"התמחור נקבע לפי היקף השירות — מספר ימים בשבוע, מספר שעות, ומורכבות המצב. בשיחת ההיכרות נעבור על המצב הספציפי ונציג הצעת מחיר ברורה ומלאה. שקיפות מלאה מההתחלה."},{q:"האם השירות זמין גם כליווי משלים?",a:"כן. אנחנו זמינים גם כשירות משלים — אם למשפחה כבר יש מערכת תמיכה במקום, אנחנו עובדים בתוכה תוך שיתוף פעולה מלא עם נותני השירות הנוספים, להבטחת הבריאות והרווחה הטובה ביותר למטופל."},{q:"יש הפניות?",a:"כן — הפניות מקצועיות וממשפחות מטופלים זמינות לבקשה. נשמח לחבר אתכם ישירות עם משפחות שאנחנו עובדים או עבדנו איתן."}]},cta:{headline:"תפסיקו לתאם. תתחילו לסמוך.",sub:"שיחת ייעוץ של 30 דקות, ללא עלות. נבין יחד אם השירות מתאים לאבא שלכם — ואם לא, נכוון אתכם לאן שכן יתאים.",primary:"קביעת שיחת ייעוץ",secondary:"צרו קשר בוואטסאפ"},footer:{tagline:"ניהול טיפול גריאטרי פרטי. בכבוד. בבית. כל יום.",contact:"צור קשר",areasTitle:"אזורי שירות ושעות",areas:"רמת בית שמש א׳ \xb7 בית שמש \xb7 ביתר עילית \xb7 מודיעין עילית \xb7 ירושלים",hours:"א׳-ה׳ 7:00-19:00 \xb7 ו׳ 7:00-13:00 \xb7 זמינות לחירומים גם מחוץ לשעות",copyright:"\xa9 2026 Eitzikna — ניהול טיפול גריאטרי פרטי. כל הזכויות שמורות."}},en:{nav:{services:"Services",pillars:"Methodology",conditions:"Conditions",about:"About",contact:"Contact",cta:"Free Consultation"},hero:{headline:"Your Father Deserves More Than a Caregiver",sub:"Eitzikna provides full-day, in-home private geriatric care management. Our practitioners personally implement the medical care plan, attend appointments alongside the treating physicians, and report to the family in writing every visit day.",ctaPrimary:"Schedule a Consultation"},problem:{eyebrow:"The Challenge",headline:"Caring for an Aging Parent Shouldn't Consume Your Life",body:"The physical therapist visits once a week and leaves instructions. The dietitian sends a meal plan. The doctor prescribes medication. But who actually implements all of it day to day? Who documents? Who coordinates the entire medical team? Usually — you do. From the office, from abroad, at night."},approach:{eyebrow:"Our Clinical Approach",headline:"Hands-On Implementation. Daily Documentation. Full Clinical Accountability.",body:"Instead of coordinating five different specialists and hoping the information flows between them — Eitzikna attends every medical appointment, executes every prescribed treatment, documents continuously, and reports back to you in writing every visit day.",bullets:["Hands-on implementation of every prescribed PT and OT exercise, directly under the specialist's instruction","Preparation of medical-diet meals; monitoring of intake, hydration, and output; early identification of clinical signs","Full medication schedule management — dosing, administration, side-effect monitoring, pharmacy coordination","Direct attendance at medical appointments alongside the family physician, geriatrician, PT, and dietitian","Daily clinical documentation — symptoms, vitals, cognition, mood, and treatment progression","Structured family reporting via WhatsApp, email, or call — at your preferred cadence"]},services:{title:"What We Execute Every Visit Day",subtitle:"A comprehensive treatment plan, executed in-home, with direct clinical experience.",items:[{title:"Clinical PT Implementation",desc:"Attendance at every professional PT session, learning the technique directly from the specialist, and precise execution of the routine in-home throughout the week — at the prescribed intensity, in the prescribed sequence, without gaps in the treatment schedule."},{title:"Occupational & Cognitive Therapy",desc:"Board games, gentle motor activities, memory exercises, and functional task practice — selected based on current cognitive status, modulated as the situation evolves."},{title:"Medical Nutrition & Meal Preparation",desc:"In coordination with the clinical dietitian. Tracking of intake, hydration, and output — early identification of dehydration, constipation, and malabsorption — and complete implementation of the medically-tailored menu."},{title:"Medication Management & Compliance",desc:"Full oversight of the medication schedule, dose verification, side-effect monitoring, prescription refill coordination, and direct communication with the pharmacy and prescribing physician."},{title:"Mobility, Transfers & Fall Prevention",desc:"Skilled in safe transfers, assisted ambulation, and home environment adaptation. Specialized training for Parkinson's, post-stroke, and limited-mobility patients."},{title:"Spiritual & Traditional Care",desc:"Daily tefilla, escorted shul attendance, learning Gemara or Chumash, and preserving the spiritual structure that anchors the patient's daily life. Tailored to the family's tradition and background."},{title:"Therapeutic Outdoor Activity",desc:"Daily walks, park outings, controlled exposure to fresh air and social environment, community errands — an integral part of the clinical plan."},{title:"Deep Companionship & Cognitive Presence",desc:"Active, attentive presence — not just being in the room. Conversations, shared singing, recording personal history as a family memoir, patient listening. Cognitive stimulation through real human connection."},{title:"Structured Rest & Daily Restoration",desc:"Scheduled rest and sleep windows, calm environment, properly timed breaks between activities — to balance physical and cognitive load throughout the full care day."}]},pillars:{title:"The Four Pillars of Care",subtitle:"A structured clinical methodology — the foundation of every care plan we design and execute.",items:[{number:"01",title:"Medical Supervision & Personal Care",summary:"The day-to-day clinical management of the patient's health — from the first morning dose to the evening summary report.",details:[{h:"Medication Management",b:"Full oversight of schedules, dose verification, side-effect tracking, coordination with the pharmacy and prescribing physician, and continuous protocol-compliance monitoring."},{h:"Hygiene with Dignity",b:"Comprehensive support with dressing, bathing, and incontinence care — delivered with strict respect for the patient's dignity and physical comfort in every action."},{h:"Mobility & Safety",b:"Trained in safe transfers, fall-risk assessment, home environment adaptation, and assisted ambulation — preserving functional independence."},{h:"Clinical Documentation & Reporting",b:"Detailed daily records: symptoms, vitals, doses, PT performance, dietary intake, mood and cognition — provided to the medical team and the family."}]},{number:"02",title:"Gastrointestinal & Nutritional Foundation",summary:"Stable GI and nutritional status is a prerequisite for medication absorption, rehabilitation tolerance, and chronic disease management. We treat it as the foundation of every care plan.",details:[{h:"Intake & Hydration Tracking",b:"Daily monitoring of caloric and fluid intake against the prescribed medical diet, with early identification of trends that affect medication efficacy, rehabilitation, and metabolic stability."},{h:"GI Function & Output",b:"Regular tracking of GI function and elimination patterns. Early identification of constipation, malabsorption, and signs of dehydration — escalated to the physician before clinical deterioration."},{h:"Clinical Coordination",b:"Direct coordination with the prescribing dietitian or nutritionist on menu, supplementation, and modifications based on changes in medical status."}]},{number:"03",title:"PT Facilitation & Therapeutic Movement",summary:"Present at sessions with the specialist — learning the technique directly. Full implementation at home throughout the week. No exercise lost in translation between visits.",details:[{h:"Clinical Implementation",b:"Attendance at professional PT and OT sessions to learn routines directly from the specialist — ensuring exercises are executed correctly at home, at the prescribed intensity and dosing."},{h:"Integrated Mobility",b:"Coordinated stretching routines and therapeutic massage throughout the full care day — preserving joint mobility, range of motion, and circulation."},{h:"Adaptive Routines",b:"When the standard routine isn't viable, substitution with pre-coordinated alternative movements — maintaining therapeutic continuity without overexertion."}]},{number:"04",title:"Structure, Outings & Cognitive Presence",summary:"A structured day. Outings with purpose. Real human presence — from someone who knows the patient deeply.",details:[{h:"Active Routine",b:"A predictable daily schedule that prioritizes outings and activities specifically designed for physical and cognitive stimulation — at the pace right for each patient."},{h:"Deep Companionship",b:"Full, attentive presence. Conversations, shared singing, recording personal history as a family memoir, patient listening — real human connection, not just physical presence."},{h:"Spiritual Support",b:"Daily tefilla and learning, escorted shul attendance, preservation of the family's spiritual life — tailored to the patient's background and tradition."}]}]},conditions:{title:"Conditions & Areas of Care",subtitle:"Specialization in the management of physically and cognitively complex cases.",items:[{title:"Parkinson's Disease",desc:'Management across all disease stages, L-Dopa dosing protocols, activity timing within "on" windows, navigation of "off" periods.'},{title:"Dementia & Cognitive Decline",desc:"Alzheimer's, vascular dementia, Lewy body, frontotemporal. Structured routines, cognitive stimulation, and behavioral change management across disease progression."},{title:"Post-Stroke Recovery",desc:"Rehabilitation PT implementation, aphasia management, motor recovery, and coordination with the physiatrist and the multidisciplinary team."},{title:"Limited Mobility",desc:"Wheelchair-bound or mobility-impaired patients — safe transfers, pressure-injury prevention, range-of-motion preservation."},{title:"Chronic Disease Management",desc:"Diabetes, heart disease, COPD, renal insufficiency — medication management, daily vital-sign monitoring, early escalation on clinical change."},{title:"Post-Hospital Discharge",desc:"Safe bridge between hospital and home — discharge coordination, full implementation of discharge instructions, and monitoring for potential complications."}]},how:{title:"How to Begin",steps:[{t:"Introductory Call",b:"A 30-minute conversation with you to understand the medical situation, the daily challenges, and the expectations of the engagement. Free, no obligation."},{t:"Assessment Visit & Plan Build",b:"In-home visit with the patient, review of medical records, and meeting with the family physician where appropriate — toward construction of a complete, tailored weekly care plan."},{t:"Implementation, Documentation, Reporting",b:"Full-day in-home care at the agreed cadence, full execution of the medical plan, ongoing clinical documentation, and structured reporting to the family — WhatsApp, email, or call."}]},why:{title:"What Makes This Different",colA:"Standard Caregiver",colB:"Care Manager (Remote)",colC:"Eitzikna",rows:[["Generally not Jewish; not familiar with Jewish life and tradition","May or may not be familiar with the patient's Jewish background","Jewish, Torah-observant, fully fluent in the Jewish patient context"],["Bedside presence only; does not implement clinical treatments","Coordinates remotely; does not personally execute treatments","Hands-on, in-home implementation of every prescribed treatment"],["Does not attend medical appointments","Phone or email coordination; no physical attendance","Attends medical appointments alongside the patient and physicians"],["No coordination with the medical team","Periodic coordination, primarily administrative","Direct, ongoing coordination with the entire care team"],["No daily clinical documentation","Monthly notes only","Daily clinical logs — symptoms, doses, vitals, cognition, treatment progression"],["No family reporting","Monthly summaries","Structured reporting every visit day"],["Accountability limited to physical presence","Accountability limited to coordination","Full clinical accountability across the day-time care window"]]},family:{title:"We Work in Full Partnership With the Family",subtitle:"Full transparency and continuous communication — not a feature, but the core of the service.",row1:{t:"Family Reporting Every Visit Day",b:"Every visit day — a structured summary: what was performed, how your father felt, whether symptoms changed, what was decided. Delivered at your preferred cadence — WhatsApp, email, or call."},row2:{t:"Documented, Transparent Care Plan",b:"Every decision, dose, and exercise — documented in writing. The family has full access to the care record at any moment, and knows exactly where your father stands."},closing:"Because real care for a parent begins with the family's trust."},founder:{eyebrow:"The Person Behind the Service",headline:"Dani Dratler — Founder of Eitzikna",body:"Eitzikna is led by Dani Dratler — a Jewish, Torah-observant practitioner based in Ramat Beit Shemesh, dedicated to providing hands-on geriatric care to Jewish patients in their homes.\n\nOur approach is built on patient advocacy: seeing every situation from the patient's perspective and acting in their best interest at every moment. We take a proactive role in supporting comfort, health, safety, and overall well-being. Through empathy, attentive listening, and full presence, every patient feels understood, supported, and truly cared for.\n\nWe are reliable, attentive, and quick to learn each patient's unique routines, preferences, and needs. The shared Jewish identity allows for genuine understanding of the spiritual life, the dynamics of the Jewish family, and the communal framework — everything that constitutes real care that respects the patient.",credentials:"Based in Ramat Beit Shemesh Aleph \xb7 Serving Beit Shemesh, Beitar Illit, Modiin Illit & Jerusalem"},references:{title:"What Families Are Saying",subtitle:"Professional and family references — available on request.",body:"We'd be glad to put you directly in touch with families we're currently working with or have worked with — so you hear, unfiltered, what this service actually looks like day to day.",cta:"Contact us to request references"},faq:{title:"Frequently Asked Questions",items:[{q:"What's the difference between private geriatric care management and a regular caregiver?",a:"A regular caregiver is present in the home and provides basic assistance. Private geriatric care management is a complete clinical service — our practitioners personally execute the prescribed treatments, attend medical appointments, document daily, and report to the family. The service is more comprehensive, more proactive, and clinically accountable."},{q:"What conditions does Eitzikna have the most experience with?",a:"Parkinson's disease across all stages (including L-Dopa dosing protocols and on/off window management), dementia (Alzheimer's, vascular, Lewy body, frontotemporal), post-stroke recovery, mobility limitations, and management of complex chronic disease."},{q:"Do you work with my father's existing doctors?",a:"Absolutely — it's a central part of the service. We attend appointments with the family physician, geriatrician, physical therapist, and dietitian. We receive instructions directly, implement them at home, and report back. The existing medical team gets accurate, consistent information."},{q:"What does daily reporting look like?",a:"Every visit day: doses administered, symptoms noted, changes in mood or cognition, PT execution (which exercises, how many reps), food and fluid intake, output, and activities. Delivered via WhatsApp, email, or call — at the cadence you request."},{q:"What areas do you serve?",a:"Ramat Beit Shemesh Aleph, Beit Shemesh, Beitar Illit, Modiin Illit, and Jerusalem. Available short-term in additional areas — please reach out to discuss."},{q:"How long is the daily care window?",a:"We provide full day-time presence throughout the day. The service is structured to be the primary daytime care relationship for the patient. For families that also need overnight support, we coordinate easily with additional providers."},{q:"What happens in an emergency?",a:"In a medical emergency — call MDA immediately. We are reachable by phone during the day for any urgent question, and during the visit itself we escalate anything requiring immediate medical attention to the appropriate physician."},{q:"How much does it cost?",a:"Pricing is set based on the scope of service — number of days per week, number of hours, and complexity of the situation. During the introductory call we go over the specific case and present a clear, complete proposal. Full transparency from the outset."},{q:"Is the service available as complementary care?",a:"Yes. We are equally available as complementary care — if a family already has support systems in place, we work within them in full collaboration with the other providers, ensuring the greatest health and wellness for the patient."},{q:"Do you have references?",a:"Yes — professional references and references from client families are available on request. We're happy to put you directly in touch with families we're currently working with or have worked with."}]},cta:{headline:"Stop Coordinating. Start Trusting.",sub:"A 30-minute consultation, no cost. Together we'll see if the service is right for your father — and if not, we'll point you to where it would be.",primary:"Schedule a Consultation",secondary:"Contact via WhatsApp"},footer:{tagline:"Private geriatric care management. With dignity. At home. Every day.",contact:"Contact",areasTitle:"Service Areas & Hours",areas:"Ramat Beit Shemesh Aleph \xb7 Beit Shemesh \xb7 Beitar Illit \xb7 Modiin Illit \xb7 Jerusalem",hours:"Sun-Thu 7am-7pm \xb7 Fri 7am-1pm \xb7 After-hours availability for emergencies",copyright:"\xa9 2026 Eitzikna — Private Geriatric Care Management. All rights reserved."}}},n="054-841-5109",o="+972 54-841-5109",r="danielmoshedratler@gmail.com",s="https://wa.me/".concat(o.replace(/\D/g,"")),l="tel:".concat(n.replace(/\s|-/g,""))}}]);